import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { db } from "@/lib/db";
import { put } from "@vercel/blob";
import sharp from "sharp";
import { safeFileExtension, safeBlobPathname, uniqueBlobFilename } from "@/lib/blob-paths";

/**
 * POST /api/events/[slug]/images
 * Multipart upload. Form fields:
 *   - files: File[] (one or more image files)
 *   - caption (optional, applied to all images in this request)
 *
 * Uploads files to Vercel Blob at `events/<eventId>/<cuid>.jpg`.
 * Stores the returned Blob URL in EventImage.fileUrl.
 *
 * IMPORTANT: On Vercel's serverless filesystem, public/ is READ-ONLY at
 * runtime — we MUST use Vercel Blob (or another object storage provider)
 * for image uploads. Writing to public/uploads/... was the old approach
 * and failed with EROFS/EACCES.
 *
 * EXIF: Mobile phones save photos in sensor-native orientation and embed
 * an EXIF orientation tag. Browsers honor this for display but `sharp`
 * does NOT auto-apply it — you have to call `.rotate()` (no argument)
 * explicitly. Without this, photos uploaded from a phone in portrait
 * come out sideways. Here we call `.rotate()` first, then resize/re-encode,
 * so the saved file is always visually upright.
 */
export async function POST(
  req: NextRequest,
  { params }: { params: Promise<{ slug: string }> }
) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.email) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { slug } = await params;
  const event = await db.event.findUnique({ where: { slug } });
  if (!event) return NextResponse.json({ error: "Event not found" }, { status: 404 });

  const user = await db.user.findUnique({ where: { email: session.user.email } });
  if (!user) return NextResponse.json({ error: "User not found" }, { status: 403 });

  let formData: FormData;
  try {
    formData = await req.formData();
  } catch (err) {
    // Most common cause: the multipart body exceeded Vercel's 4.5 MB
    // serverless function body limit. The platform returns HTTP 413
    // with a non-JSON body, which surfaces as a confusing "string did
    // not match the expected pattern" error in the browser. Catch it
    // here and return a clear, actionable JSON message instead.
    console.error("[upload] req.formData() failed:", err);
    return NextResponse.json(
      {
        error:
          "Upload failed — the total request body was too large (Vercel limits each request to ~4.5 MB). " +
          "Please upload fewer photos at once, or upload them one at a time.",
      },
      { status: 413 }
    );
  }
  const files = formData.getAll("files").filter((f): f is File => f instanceof File);
  const caption = formData.get("caption") as string | null;

  if (files.length === 0) {
    return NextResponse.json({ error: "No files provided" }, { status: 400 });
  }

  // Validate image MIME types. We also accept `image/jpg` (some Android
  // cameras send this instead of the official `image/jpeg`) and fall back
  // to checking the file extension when the MIME type is missing or
  // generic (e.g. `application/octet-stream` from desktop drag-drop).
  const allowedMime = ["image/jpeg", "image/jpg", "image/png", "image/webp", "image/gif", "image/heic", "image/heif", "image/avif"];
  const allowedExt = ["jpg", "jpeg", "png", "webp", "gif", "heic", "heif", "avif"];
  for (const f of files) {
    const ext = safeFileExtension(f.name, f.type, "");
    if (!allowedMime.includes(f.type) && !allowedExt.includes(ext)) {
      return NextResponse.json(
        { error: `Unsupported file type: ${f.name} (${f.type || ext})` },
        { status: 400 }
      );
    }
  }

  // Compute starting slideOrder
  const maxOrder = await db.eventImage.aggregate({
    where: { eventId: event.id },
    _max: { slideOrder: true },
  });
  let nextOrder = (maxOrder._max.slideOrder ?? -1) + 1;

  type CreatedImage = {
    fileName: string;
    fileUrl: string;
    fileSize: number;
    width: number | null;
    height: number | null;
    mimeType: string;
  };

  const created: CreatedImage[] = [];
  for (const file of files) {
    // Read file buffer
    const buf = Buffer.from(await file.arrayBuffer());

    // Use sharp to apply EXIF orientation, get dimensions, and re-encode.
    let width: number | null = null;
    let height: number | null = null;
    let uploadBuf: Buffer = buf;
    // Compute a safe extension up front (handles non-ASCII filenames
    // like Hebrew "תמונה" that have no extension — the old code would
    // turn the entire filename into the "extension" and Vercel Blob
    // would reject the pathname). sharp normally re-encodes as JPEG so
    // we override this to "jpg" inside the try block below.
    let uploadExt = safeFileExtension(file.name, file.type, "jpg");
    let mimeType = file.type;

    try {
      // .rotate() with no angle auto-applies EXIF orientation
      const rotated = sharp(buf).rotate();
      const meta = await rotated.metadata();
      width = meta.width ?? null;
      height = meta.height ?? null;

      // Re-encode as JPEG for storage efficiency + guaranteed browser support
      uploadBuf = await rotated
        .resize({ width: 2200, height: 2200, fit: "inside", withoutEnlargement: true })
        .jpeg({ quality: 86, mozjpeg: true })
        .toBuffer();
      uploadExt = "jpg";
      mimeType = "image/jpeg";
    } catch (err) {
      console.warn("[upload] sharp processing failed, uploading original:", err);
      // uploadBuf stays as the original buffer; uploadExt stays as the
      // safe extension derived above (NOT the raw extension from the
      // filename — that's the bug we're fixing).
    }

    const blobName = safeBlobPathname(
      "events",
      event.id,
      uniqueBlobFilename(uploadExt)
    );

    try {
      const blob = await put(blobName, uploadBuf, {
        access: "public",
        contentType: mimeType,
        addRandomSuffix: false,
      });

      created.push({
        fileName: file.name,
        fileUrl: blob.url,
        fileSize: uploadBuf.length,
        width,
        height,
        mimeType,
      });
    } catch (err) {
      console.error("[upload] Vercel Blob put failed:", err);
      return NextResponse.json(
        { error: `Failed to upload ${file.name}: ${err instanceof Error ? err.message : String(err)}` },
        { status: 500 }
      );
    }
  }

  // Insert DB rows
  const images: Awaited<ReturnType<typeof db.eventImage.create>>[] = [];
  for (const c of created) {
    const img = await db.eventImage.create({
      data: {
        eventId: event.id,
        uploaderId: user.id,
        fileName: c.fileName,
        fileUrl: c.fileUrl,
        fileSize: c.fileSize,
        width: c.width,
        height: c.height,
        mimeType: c.mimeType,
        caption: caption || null,
        slideOrder: nextOrder++,
      },
    });
    images.push(img);
  }

  return NextResponse.json({ images, count: images.length });
}

/**
 * GET /api/events/[slug]/images
 * Returns all images for the event, ordered by slideOrder.
 */
export async function GET(
  _req: NextRequest,
  { params }: { params: Promise<{ slug: string }> }
) {
  const { slug } = await params;
  const event = await db.event.findUnique({ where: { slug } });
  if (!event) return NextResponse.json({ error: "Event not found" }, { status: 404 });

  const images = await db.eventImage.findMany({
    where: { eventId: event.id },
    orderBy: { slideOrder: "asc" },
    include: {
      uploader: { select: { id: true, name: true, email: true, image: true } },
      speakers: { select: { id: true, name: true, role: true, company: true } },
    },
  });
  return NextResponse.json({ images });
}
